trigger TriggerOnEvent on Event (after insert, after update) {
    if(staticVar.Event_RunOnce == true) {
        // Query Record Type IDs for Account types
        Id accRecordTypeHO = [
            SELECT Id 
            FROM RecordType 
            WHERE Name = 'Home Owner' 
            AND SobjectType = 'Account' 
            AND IsActive = true 
            LIMIT 1
        ].Id;

        Id accRecordTypeBU = [
            SELECT Id 
            FROM RecordType 
            WHERE Name = 'Builder' 
            AND SobjectType = 'Account' 
            AND IsActive = true 
            LIMIT 1
        ].Id;

        // Build a wrapper for each event record from the trigger
        List<EventWrapper> wrappers = new List<EventWrapper>();
        for (Event ev : Trigger.new) {
            // Wrap the event so we can pass it along with related records
            EventWrapper wrap = new EventWrapper(ev);

            // Create an Account if needed (WhatId is null and required fields are populated)
            if (ev.WhatId == null &&
                ev.New_Account_Name_Last_Name__c != null &&
                ev.New_Account_Billing_Email_Address__c != null &&
                ev.New_Account_Business_Internal_Role__c != null &&
                ev.New_Account_Record_Type__c != null) {

                    Account a = new Account();
                    a.bpmpro3__Billing_Email_Address__c = ev.New_Account_Billing_Email_Address__c;
                    a.bpmpro3__Business_Internal_Role__c = ev.New_Account_Business_Internal_Role__c;
                    a.Record_Type_Custom__c = ev.New_Account_Record_Type__c;
                    a.Name = ev.New_Account_Name_Last_Name__c;
                    a.RecordTypeId = accRecordTypeBU;

                    /*
* Comment out section for 'Calendar Customisation Revision 1' March 18, 2025 
// Set fields based on Account Record Type
if (ev.New_Account_Record_Type__c == 'Home Owner' && accRecordTypeHO != null) {
a.RecordTypeId = accRecordTypeHO;
a.LastName = ev.New_Account_Name_Last_Name__c;
a.FirstName = ev.New_Account_First_Name__c;
} else if (ev.New_Account_Record_Type__c == 'Builder' && accRecordTypeBU != null) {
a.RecordTypeId = accRecordTypeBU;
a.Name = ev.New_Account_Name_Last_Name__c;
if (ev.New_Account_First_Name__c != null) {
a.Name = ev.New_Account_First_Name__c + ' ' + ev.New_Account_Name_Last_Name__c;
}
}*/
                    wrap.account = a;
                }

            // Create a Contact if needed (WhoId is null and required field is populated)
            if (ev.WhoId == null &&
                ev.New_Contact_Last_Name__c != null) {

                    Contact c = new Contact();
                    c.FirstName = ev.New_Contact_First_Name__c;
                    c.LastName = ev.New_Contact_Last_Name__c;
                    c.Email = ev.New_Account_Billing_Email_Address__c;
                    c.Phone = ev.New_Contact_Phone__c;
                    c.MobilePhone = ev.New_Contact_Mobile__c;
                    wrap.contact = c;
                }

            wrappers.add(wrap);
        }

        // Bulk insert Accounts (if any) and update the wrapper with the new Account Id
        List<Account> accountsToInsert = new List<Account>();
        for (EventWrapper wrap : wrappers) {
            if (wrap.account != null) {
                accountsToInsert.add(wrap.account);
            }
        }
        if (!accountsToInsert.isEmpty()) {
            insert accountsToInsert;
            Integer accountIndex = 0;
            for (EventWrapper wrap : wrappers) {
                if (wrap.account != null) {
                    // Retrieve the inserted account with its Id and store in the wrapper variable
                    wrap.account = accountsToInsert[accountIndex];
                    wrap.updatedWhatId = wrap.account.Id;
                    accountIndex++;
                }
            }
        }

        // Bulk insert Contacts (if any) and update the wrapper with the new Contact Id
        List<Contact> contactsToInsert = new List<Contact>();
        for (EventWrapper wrap : wrappers) {
            if (wrap.contact != null) {
                // If an Account was created, assign its Id to the Contact’s AccountId field
                if (wrap.updatedWhatId != null) {
                    wrap.contact.AccountId = wrap.updatedWhatId;
                }
                contactsToInsert.add(wrap.contact);
            }
        }
        if (!contactsToInsert.isEmpty()) {
            insert contactsToInsert;
            Integer contactIndex = 0;
            for (EventWrapper wrap : wrappers) {
                if (wrap.contact != null) {
                    wrap.contact = contactsToInsert[contactIndex];
                    wrap.updatedWhoId = wrap.contact.Id;
                    contactIndex++;
                }
            }
        }

        // Create new Event instances for update to avoid modifying read-only records.
        // If updatedWhatId or updatedWhoId is not set, preserve the existing value from the event.
        List<Event> eventsToUpdate = new List<Event>();
        for (EventWrapper wrap : wrappers) {
            Id newWhatId = wrap.updatedWhatId != null ? wrap.updatedWhatId : wrap.ev.WhatId;
            Id newWhoId = wrap.updatedWhoId != null ? wrap.updatedWhoId : wrap.ev.WhoId;

            Event evUpdate = new Event(
                Id = wrap.ev.Id,
                WhatId = newWhatId,
                WhoId = newWhoId,
                New_Account_Name_Last_Name__c = null,
                New_Account_Billing_Email_Address__c = null,
                New_Account_Business_Internal_Role__c = null,
                New_Account_Record_Type__c = null,
                New_Account_First_Name__c = null,
                New_Contact_First_Name__c = null,
                New_Contact_Last_Name__c = null,
                New_Contact_Phone__c = null,
                New_Contact_Mobile__c = null
            );
            eventsToUpdate.add(evUpdate);
        }
        if (!eventsToUpdate.isEmpty()) {
            staticVar.Event_RunOnce = false;
            update eventsToUpdate;
        }
    }

    // Wrapper class to hold each Event along with its related Account and Contact objects,
    // as well as updated field values that we want to use in our update DML.
    private class EventWrapper {
        public Event ev;
        public Account account;
        public Contact contact;
        public Id updatedWhatId;
        public Id updatedWhoId;

        public EventWrapper(Event e) {
            this.ev = e;
        }
    }
}

