@isTest
public class TriggerOnEventTest {

    @isTest static void testCreateAccountAndContact() {
        // Set the static flag so that the trigger will run
        staticVar.Event_RunOnce = true;

        // Create an Event record with the required fields to trigger new Account and Contact creation.
        Event testEvent = new Event(
            Subject = 'Test Event - Create New Records',
            // Set event start and end times.
            StartDateTime = System.now().addDays(1),
            EndDateTime = System.now().addDays(1).addHours(1),
            // Fields used for creating a new Account.
            New_Account_Name_Last_Name__c = 'TestAccountLast',
            New_Account_Billing_Email_Address__c = 'test@example.com',
            New_Account_Business_Internal_Role__c = 'client',
            New_Account_Record_Type__c = 'Builder',
            New_Account_First_Name__c = 'TestAccountFirst',
            // Fields used for creating a new Contact.
            New_Contact_First_Name__c = 'TestContactFirst',
            New_Contact_Last_Name__c = 'TestContactLast'
        );
        insert testEvent;

        // Query the updated event record.
        Event updatedEvent = [
            SELECT Id, WhatId, WhoId,
                   New_Account_Name_Last_Name__c,
                   New_Account_Billing_Email_Address__c,
                   New_Account_Business_Internal_Role__c,
                   New_Account_Record_Type__c,
                   New_Account_First_Name__c,
                   New_Contact_First_Name__c,
                   New_Contact_Last_Name__c
              FROM Event
             WHERE Id = :testEvent.Id
        ];

        // Verify that the trigger has created new Account and Contact records and updated the Event.
        System.assertNotEquals(null, updatedEvent.WhatId, 'WhatId should be set by trigger.');
        System.assertNotEquals(null, updatedEvent.WhoId, 'WhoId should be set by trigger.');

        // Verify that the custom fields used for new Account/Contact creation have been reset.
        System.assertEquals(null, updatedEvent.New_Account_Name_Last_Name__c, 'New Account Last Name should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Account_Billing_Email_Address__c, 'New Account Billing Email should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Account_Business_Internal_Role__c, 'New Account Business Internal Role should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Account_Record_Type__c, 'New Account Record Type should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Account_First_Name__c, 'New Account First Name should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Contact_First_Name__c, 'New Contact First Name should be null after processing.');
        System.assertEquals(null, updatedEvent.New_Contact_Last_Name__c, 'New Contact Last Name should be null after processing.');
    }

}

public class staticVar {
	public static Boolean Event_RunOnce = true;
}
